 36→static inline void* test_malloc_cacheable(size_t size, char *bufName, void **ptrOrigin)
 37→{
 38→    const size_t alignBytes = 64;
 39→
 40→    //Note. remember to backup the starting address of malloced memory for later memory releasing
 41→    void *ptrAligned = NULL;
 42→    *ptrOrigin = NULL;
 43→    if (size)
 44→    {
 45→        size_t allocBytes = size + (alignBytes-1);
 46→        *ptrOrigin = (void*)malloc(allocBytes);
 47→        if(*ptrOrigin == NULL)
 48→        {
 49→            printf("Error on %s malloc!!!\n", bufName);
 50→            // exit(NDS_FAILURE);
 51→        }
 52→        else
 53→        {
 54→            ptrAligned = (void *)(((size_t)*ptrOrigin + (alignBytes-1)) & ~((alignBytes-1)));
 55→        }
 56→        DBG_MSG("%s is located in [0x%" PRIxPTR " ~ 0x%" PRIxPTR "], ptrAligned=0x%" PRIxPTR ", allocBytes=%zu\n", bufName, (uintptr_t)*ptrOrigin, (uintptr_t)(*ptrOrigin+allocBytes-1), (uintptr_t)ptrAligned, allocBytes);
 57→    }
 58→
 59→    return ptrAligned;
 60→}
